@@ -5996,6 +5998,34 @@ func (mset *stream) processJetStreamMsg(subject, reply string, hdr, msg []byte,
 	// If here we succeeded in storing the message.
 	mset.mu.Unlock()

+	// Track uncommitted batch messages for isolated reads.
+	// If this message is part of a batch that hasn't committed yet,
+	// mark it as uncommitted so readers won't see it.
+	if batchId != _EMPTY_ {
+		hasCommit := len(sliceHeader(JSBatchCommit, hdr)) > 0
+		if !hasCommit {
+			// This is a batch message without commit, mark as uncommitted
+			mset.batchUncommittedMu.Lock()
+			if mset.batchUncommitted == nil {
+				mset.batchUncommitted = make(map[uint64]struct{})
+			}
+			mset.batchUncommitted[seq] = struct{}{}
+			mset.batchUncommittedMu.Unlock()
+		} else {
+			// This is the commit message - mark all messages in this batch as committed
+			// by removing them from the uncommitted map.
+			// The batch spans from (seq - batchSeq + 1) to seq.
+			mset.batchUncommittedMu.Lock()
+			if mset.batchUncommitted != nil && batchSeq > 0 {
+				startSeq := seq - batchSeq + 1
+				for i := startSeq; i <= seq; i++ {
+					delete(mset.batchUncommitted, i)
+				}
+			}
+			mset.batchUncommittedMu.Unlock()
+		}
+	}
