// Test file to reproduce isolated reads issue with batch publish
package server

import (
	"fmt"
	"strconv"
	"sync"
	"sync/atomic"
	"testing"
	"time"

	"github.com/nats-io/nats.go"
)

// TestJetStreamAtomicBatchPublishIsolatedReads tests that readers cannot observe
// partial batch effects during batch publishing
func TestJetStreamAtomicBatchPublishIsolatedReads(t *testing.T) {
	c := createJetStreamClusterExplicit(t, "R3S", 3)
	defer c.shutdown()

	nc, js := jsClientConnect(t, c.randomServer())
	defer nc.Close()

	cfg := &StreamConfig{
		Name:               "TEST",
		Subjects:           []string{"foo"},
		Storage:            FileStorage,
		AllowAtomicPublish: true,
		Replicas:           3,
	}
	_, err := jsStreamCreate(t, nc, cfg)
	require_NoError(t, err)

	// Start a reader goroutine that continuously reads messages
	var readErrors atomic.Int32
	var wg sync.WaitGroup
	stopReading := make(chan struct{})

	wg.Add(1)
	go func() {
		defer wg.Done()
		for {
			select {
			case <-stopReading:
				return
			default:
				// Try to read messages - should only see complete batches
				si, err := js.StreamInfo("TEST")
				if err != nil {
					continue
				}

				// Check if we can read messages from start to end
				// With isolated reads, we should either see no batch or complete batch
				if si.State.Msgs > 0 {
					// Try to read all messages
					for seq := uint64(1); seq <= si.State.LastSeq; seq++ {
						msg, err := js.GetMsg("TEST", seq)
						if err != nil {
							// Message might be deleted, that's okay
							continue
						}

						// If we see a message with Nats-Batch-Id header,
						// we need to verify the entire batch is visible
						batchId := msg.Header.Get("Nats-Batch-Id")
						if batchId != "" {
							batchSeqStr := msg.Header.Get("Nats-Batch-Sequence")
							if batchSeqStr == "" {
								continue
							}
							batchSeq, _ := strconv.Atoi(batchSeqStr)

							// If this is not the first message in batch,
							// the previous messages must also be visible
							if batchSeq > 1 {
								// Check if we can read previous message in batch
								prevMsg, err := js.GetMsg("TEST", seq-1)
								if err != nil {
									// Previous message not visible but current is!
									// This violates isolation
									t.Logf("Isolation violation: seq=%d in batch %s (bseq=%d) is visible, but previous message is not: %v",
										seq, batchId, batchSeq, err)
									readErrors.Add(1)
								} else {
									// Verify previous message is part of same batch
									prevBatchId := prevMsg.Header.Get("Nats-Batch-Id")
									if prevBatchId != batchId {
										t.Logf("Isolation violation: seq=%d in batch %s, but seq=%d is in different batch %s",
											seq, batchId, seq-1, prevBatchId)
										readErrors.Add(1)
									}
								}
							}
						}
					}
				}
				time.Sleep(10 * time.Millisecond)
			}
		}
	}()

	// Publish a batch of messages while reader is running
	batchSize := 10
	m := nats.NewMsg("foo")
	m.Header.Set("Nats-Batch-Id", "test-batch")

	for seq := 1; seq <= batchSize; seq++ {
		m.Data = []byte(fmt.Sprintf("msg-%d", seq))
		m.Header.Set("Nats-Batch-Sequence", strconv.Itoa(seq))

		if seq == batchSize {
			m.Header.Set("Nats-Batch-Commit", "1")
			_, err = nc.RequestMsg(m, 2*time.Second)
			require_NoError(t, err)
		} else {
			require_NoError(t, nc.PublishMsg(m))
		}

		// Small delay to increase chance of reader seeing partial state
		time.Sleep(5 * time.Millisecond)
	}

	// Wait a bit for batch to be fully applied
	time.Sleep(500 * time.Millisecond)

	// Stop reader
	close(stopReading)
	wg.Wait()

	// Check if we detected any isolation violations
	if readErrors.Load() > 0 {
		t.Fatalf("Detected %d isolation violations during batch publish", readErrors.Load())
	}

	// Verify final state - all messages should be visible
	si, err := js.StreamInfo("TEST")
	require_NoError(t, err)
	require_Equal(t, si.State.Msgs, uint64(batchSize))
}

