// Test file to reproduce isolated reads issue with batch publish
// This tests at the internal level by directly accessing store during batch apply
package server

import (
	"fmt"
	"strconv"
	"sync"
	"sync/atomic"
	"testing"
	"time"
)

// TestJetStreamAtomicBatchPublishIsolatedReadsInternal tests that readers cannot observe
// partial batch effects at the store level during batch publishing
func TestJetStreamAtomicBatchPublishIsolatedReadsInternal(t *testing.T) {
	c := createJetStreamClusterExplicit(t, "R3S", 3)
	defer c.shutdown()

	nc, _ := jsClientConnect(t, c.randomServer())
	defer nc.Close()

	cfg := &StreamConfig{
		Name:               "TEST",
		Subjects:           []string{"foo"},
		Storage:            FileStorage,
		AllowAtomicPublish: true,
		Replicas:           3,
	}
	_, err := jsStreamCreate(t, nc, cfg)
	require_NoError(t, err)

	sl := c.streamLeader(globalAccountName, "TEST")
	mset, err := sl.globalAccount().lookupStream("TEST")
	require_NoError(t, err)

	// Track isolation violations
	var violations atomic.Int32
	var wg sync.WaitGroup
	stopReading := make(chan struct{})

	// Start a reader goroutine that continuously reads from the store
	wg.Add(1)
	go func() {
		defer wg.Done()
		for {
			select {
			case <-stopReading:
				return
			default:
				// Read current state
				var state StreamState
				mset.store.FastState(&state)

				if state.Msgs > 0 {
					// Track batch IDs and their sequences we've seen
					batchMessages := make(map[string][]uint64)

					// Read all messages
					for seq := state.FirstSeq; seq <= state.LastSeq; seq++ {
						var smv StoreMsg
						sm, err := mset.store.LoadMsg(seq, &smv)
						if err != nil || sm == nil {
							continue
						}

						// Check for batch headers
						batchId := getBatchId(sm.hdr)
						if batchId != "" {
							batchSeqStr := getBatchSeq(sm.hdr)
							if batchSeqStr != "" {
								batchSeq, _ := strconv.ParseUint(batchSeqStr, 10, 64)
								batchMessages[batchId] = append(batchMessages[batchId], batchSeq)
							}
						}
					}

					// Check each batch for completeness
					for batchId, sequences := range batchMessages {
						// Check if sequences are contiguous starting from 1
						if len(sequences) > 0 {
							// Sort isn't needed since we read sequentially
							// Check if we have gaps
							for i, seq := range sequences {
								expected := uint64(i + 1)
								if seq != expected {
									t.Logf("Isolation violation: batch %s has gap - expected sequence %d, got %d. Sequences seen: %v",
										batchId, expected, seq, sequences)
									violations.Add(1)
									break
								}
							}

							// If we see a batch without Nats-Batch-Commit, it's partial
							lastSeq := sequences[len(sequences)-1]
							var smv StoreMsg
							lastMsg, err := mset.store.LoadMsg(state.FirstSeq+lastSeq-1, &smv)
							if err == nil && lastMsg != nil {
								hasCommit := getBatchCommit(lastMsg.hdr)
								if !hasCommit && len(sequences) > 0 {
									t.Logf("Isolation violation: batch %s visible without commit (sequences: %v)", batchId, sequences)
									violations.Add(1)
								}
							}
						}
					}
				}
				time.Sleep(1 * time.Millisecond) // Very frequent reads
			}
		}
	}()

	// Manually propose batch messages to Raft to simulate slow application
	// This increases the window for observing partial batches
	mset.clMu.Lock()
	batchId := "test-batch"
	hdr := genHeader(nil, "Nats-Batch-Id", batchId)

	// Send first message of batch
	hdr = setHeader("Nats-Batch-Sequence", "1", hdr)
	esm := encodeStreamMsgAllowCompressAndBatch("foo", _EMPTY_, hdr, []byte("msg1"), mset.clseq, 0, false, batchId, 1, false)
	mset.clseq++
	mset.clMu.Unlock()

	n := mset.raftNode().(*raft)
	n.sendAppendEntry([]*Entry{newEntry(EntryNormal, esm)})

	// Small delay to let first message be applied
	time.Sleep(50 * time.Millisecond)

	// Send second message separately (different proposal)
	mset.clMu.Lock()
	hdr = setHeader("Nats-Batch-Sequence", "2", hdr)
	esm = encodeStreamMsgAllowCompressAndBatch("foo", _EMPTY_, hdr, []byte("msg2"), mset.clseq, 0, false, batchId, 2, false)
	mset.clseq++
	mset.clMu.Unlock()
	n.sendAppendEntry([]*Entry{newEntry(EntryNormal, esm)})

	// Small delay to let second message be applied
	time.Sleep(50 * time.Millisecond)

	// Send commit message
	mset.clMu.Lock()
	hdr = setHeader("Nats-Batch-Sequence", "3", hdr)
	hdr = setHeader("Nats-Batch-Commit", "1", hdr)
	esm = encodeStreamMsgAllowCompressAndBatch("foo", _EMPTY_, hdr, []byte("msg3"), mset.clseq, 0, false, batchId, 3, true)
	mset.clseq++
	mset.clMu.Unlock()
	n.sendAppendEntry([]*Entry{newEntry(EntryNormal, esm)})

	// Wait for commit to be applied
	time.Sleep(200 * time.Millisecond)

	// Stop reader
	close(stopReading)
	wg.Wait()

	// Report violations
	if violations.Load() > 0 {
		t.Fatalf("Detected %d isolation violations during batch publish", violations.Load())
	}

	// Verify final state
	var state StreamState
	mset.store.FastState(&state)
	if state.Msgs != 3 {
		t.Fatalf("Expected 3 messages, got %d", state.Msgs)
	}
}

// Helper to extract batch ID from headers
func getBatchId(hdr []byte) string {
	return string(sliceHeader(JSBatchId, hdr))
}

// Helper to extract batch sequence from headers
func getBatchSeq(hdr []byte) string {
	return string(sliceHeader(JSBatchSeq, hdr))
}

// Helper to check for batch commit header
func getBatchCommit(hdr []byte) bool {
	return len(sliceHeader(JSBatchCommit, hdr)) > 0
}

// TestJetStreamAtomicBatchPublishRollupIsolation tests rollup isolation
func TestJetStreamAtomicBatchPublishRollupIsolation(t *testing.T) {
	s := RunBasicJetStreamServer(t)
	defer s.Shutdown()

	nc, js := jsClientConnect(t, s)
	defer nc.Close()

	_, err := js.AddStream(&nats.StreamConfig{
		Name:       "TEST",
		Subjects:   []string{"foo"},
		Storage:    FileStorage,
		AllowRollup: true,
	})
	require_NoError(t, err)

	// Publish some messages first
	for i := 0; i < 5; i++ {
		_, err = js.Publish("foo", []byte(fmt.Sprintf("msg%d", i)))
		require_NoError(t, err)
	}

	// Track what a reader sees
	var readCount atomic.Int32
	stopReading := make(chan struct{})
	var wg sync.WaitGroup

	wg.Add(1)
	go func() {
		defer wg.Done()
		for {
			select {
			case <-stopReading:
				return
			default:
				si, err := js.StreamInfo("TEST")
				if err == nil {
					readCount.Store(int32(si.State.Msgs))
				}
				time.Sleep(5 * time.Millisecond)
			}
		}
	}()

	// Publish a rollup message - this should atomically purge + add
	m := nats.NewMsg("foo")
	m.Data = []byte("rollup")
	m.Header.Set("Nats-Rollup", "sub")
	_, err = js.PublishMsg(m)
	require_NoError(t, err)

	time.Sleep(100 * time.Millisecond)
