			default:
				si, err := js.StreamInfo("TEST")
				if err == nil {
					readCount.Store(int32(si.State.Msgs))
				}
				time.Sleep(5 * time.Millisecond)
			}
		}
	}()

	// Publish a rollup message - this should atomically purge + add
	m := nats.NewMsg("foo")
	m.Data = []byte("rollup")
	m.Header.Set("Nats-Rollup", "sub")
	_, err = js.PublishMsg(m)
	require_NoError(t, err)

	time.Sleep(100 * time.Millisecond)
	close(stopReading)
	wg.Wait()

	// Final state should only have the rollup message
	si, err := js.StreamInfo("TEST")
	require_NoError(t, err)

	// With rollup, we should only see 1 message
	// But without isolated reads, readers might have seen:
	// - 5 messages (before rollup)
	// - 6 messages (rollup added but not yet purged)
	// - 1 message (after purge)
	t.Logf("Final message count: %d, Reader saw: %d", si.State.Msgs, readCount.Load())

	// The issue described mentions that rollup happens separately after persisting
	// So readers could observe an inconsistent state
	if si.State.Msgs != 1 {
		t.Fatalf("Expected 1 message after rollup, got %d", si.State.Msgs)
	}
}

