//go:build !skip_js_tests

// Test to demonstrate the batch publish isolated reads bug
package server

import (
	"fmt"
	"strconv"
	"sync"
	"sync/atomic"
	"testing"
	"time"

	"github.com/nats-io/nats.go"
)

// TestJetStreamBatchPublishLeaderNoIsolation demonstrates that on the leader,
// batch messages are immediately visible to readers before the batch commits
func TestJetStreamBatchPublishLeaderNoIsolation(t *testing.T) {
	c := createJetStreamClusterExplicit(t, "R3S", 3)
	defer c.shutdown()

	// Connect to the leader directly
	sl := c.randomServer()
	nc, js := jsClientConnect(t, sl)
	defer nc.Close()

	cfg := &StreamConfig{
		Name:               "TEST",
		Subjects:           []string{"foo"},
		Storage:            FileStorage,
		AllowAtomicPublish: true,
		Replicas:           3,
	}
	_, err := jsStreamCreate(t, nc, cfg)
	require_NoError(t, err)

	// Wait for leader election
	c.waitOnStreamLeader(globalAccountName, "TEST")
	leader := c.streamLeader(globalAccountName, "TEST")

	// Connect directly to the leader for reading
	ncLeader, jsLeader := jsClientConnect(t, leader)
	defer ncLeader.Close()

	var partialBatchSeen atomic.Bool
	var wg sync.WaitGroup
	stopReading := make(chan struct{})

	// Start a reader on the leader that checks for partial batches
	wg.Add(1)
	go func() {
		defer wg.Done()
		for {
			select {
			case <-stopReading:
				return
			default:
				si, err := jsLeader.StreamInfo("TEST")
				if err != nil {
					continue
				}

				if si.State.Msgs > 0 {
					// Check all visible messages for batch completeness
					batches := make(map[string]struct {
						maxSeq   uint64
						hasCommit bool
					})

					for seq := uint64(1); seq <= si.State.LastSeq; seq++ {
						msg, err := jsLeader.GetMsg("TEST", seq)
						if err != nil {
							continue
						}

						batchId := msg.Header.Get("Nats-Batch-Id")
						if batchId != "" {
							batchSeqStr := msg.Header.Get("Nats-Batch-Sequence")
							hasCommit := msg.Header.Get("Nats-Batch-Commit") != ""

							if batchSeqStr != "" {
								batchSeq, _ := strconv.ParseUint(batchSeqStr, 10, 64)

								entry := batches[batchId]
								if batchSeq > entry.maxSeq {
									entry.maxSeq = batchSeq
								}
								if hasCommit {
									entry.hasCommit = true
								}
								batches[batchId] = entry
							}
						}
					}

					// Check if we see any batch without commit
					for batchId, entry := range batches {
						if !entry.hasCommit {
							t.Logf("ISOLATION VIOLATION: Batch %s is partially visible (max seq %d) without commit on leader",
								batchId, entry.maxSeq)
							partialBatchSeen.Store(true)
						}
					}
				}
				time.Sleep(5 * time.Millisecond)
			}
		}
	}()

	// Publish a batch slowly to increase the window for observing partial state
	batchId := "test-batch-slow"
	batchSize := 5

	for seq := 1; seq <= batchSize; seq++ {
		m := nats.NewMsg("foo")
		m.Data = []byte(fmt.Sprintf("msg-%d", seq))
		m.Header.Set("Nats-Batch-Id", batchId)
		m.Header.Set("Nats-Batch-Sequence", strconv.Itoa(seq))

		if seq == batchSize {
			m.Header.Set("Nats-Batch-Commit", "1")
			_, err = nc.RequestMsg(m, 2*time.Second)
			require_NoError(t, err)
		} else {
			require_NoError(t, nc.PublishMsg(m))
			// Delay between messages to increase window for reader
			time.Sleep(20 * time.Millisecond)
		}
	}

	// Wait for batch to fully commit
	time.Sleep(200 * time.Millisecond)

	// Stop reader
	close(stopReading)
	wg.Wait()

	// Report result
	if partialBatchSeen.Load() {
		t.Logf("SUCCESS: Demonstrated isolation violation - partial batch was visible on leader")
	} else {
		t.Logf("UNCLEAR: Did not observe partial batch (may need to adjust timing)")
	}

	// Verify final state is correct
	si, err := js.StreamInfo("TEST")
	require_NoError(t, err)
	require_Equal(t, si.State.Msgs, uint64(batchSize))
}

// TestJetStreamBatchPublishDirectStoreAccess tests isolation by directly
// accessing the stream store on the leader during batch publish
func TestJetStreamBatchPublishDirectStoreAccess(t *testing.T) {
	c := createJetStreamClusterExplicit(t, "R3S", 3)
	defer c.shutdown()

	nc, _ := jsClientConnect(t, c.randomServer())
	defer nc.Close()

	cfg := &StreamConfig{
		Name:               "TEST",
		Subjects:           []string{"foo"},
		Storage:            FileStorage,
		AllowAtomicPublish: true,
		Replicas:           3,
	}
	_, err := jsStreamCreate(t, nc, cfg)
	require_NoError(t, err)

	c.waitOnStreamLeader(globalAccountName, "TEST")
	leader := c.streamLeader(globalAccountName, "TEST")

	mset, err := leader.globalAccount().lookupStream("TEST")
	require_NoError(t, err)

	var partialSeen atomic.Bool
	var wg sync.WaitGroup
	stopReading := make(chan struct{})

	// Direct store reader
	wg.Add(1)
	go func() {
		defer wg.Done()
		for {
			select {
			case <-stopReading:
				return
			default:
				var state StreamState
				mset.store.FastState(&state)

				if state.Msgs > 0 {
					batches := make(map[string]struct {
						sequences []uint64
						hasCommit bool
					})

					for seq := state.FirstSeq; seq <= state.LastSeq; seq++ {
						var smv StoreMsg
						sm, err := mset.store.LoadMsg(seq, &smv)
						if err != nil || sm == nil {
							continue
						}

						batchId := getBatchId(sm.hdr)
						if batchId != "" {
							entry := batches[batchId]
							bseq, ok := getBatchSequence(sm.hdr)
							if ok {
								entry.sequences = append(entry.sequences, bseq)
							}
							if len(sliceHeader(JSBatchCommit, sm.hdr)) > 0 {
								entry.hasCommit = true
							}
							batches[batchId] = entry
						}
					}

					// Check for incomplete batches
					for batchId, entry := range batches {
						if len(entry.sequences) > 0 && !entry.hasCommit {
							t.Logf("ISOLATION VIOLATION: Batch %s visible in store without commit (sequences: %v)",
								batchId, entry.sequences)
							partialSeen.Store(true)
						}
					}
				}
				time.Sleep(1 * time.Millisecond)
			}
		}
	}()

	// Publish batch slowly
	batchId := "direct-test-batch"
	batchSize := 5

	for seq := 1; seq <= batchSize; seq++ {
		m := nats.NewMsg("foo")
		m.Data = []byte(fmt.Sprintf("msg-%d", seq))
		m.Header.Set("Nats-Batch-Id", batchId)
		m.Header.Set("Nats-Batch-Sequence", strconv.Itoa(seq))

		if seq == batchSize {
			m.Header.Set("Nats-Batch-Commit", "1")
			_, err = nc.RequestMsg(m, 2*time.Second)
			require_NoError(t, err)
		} else {
			require_NoError(t, nc.PublishMsg(m))
			time.Sleep(20 * time.Millisecond)
		}
	}

	time.Sleep(200 * time.Millisecond)
	close(stopReading)
	wg.Wait()

	if partialSeen.Load() {
		t.Logf("SUCCESS: Demonstrated isolation violation - partial batch visible in store")
	} else {
		t.Logf("Test completed without observing partial batch")
	}
}

