// isSeqUncommitted checks if a sequence number is part of an uncommitted batch.
// This is used to implement isolated reads for batch publishing.
func (mset *stream) isSeqUncommitted(seq uint64) bool {
	mset.batchUncommittedMu.RLock()
	defer mset.batchUncommittedMu.RUnlock()
	if mset.batchUncommitted == nil {
		return false
	}
	_, uncommitted := mset.batchUncommitted[seq]
	return uncommitted
}

