// Final test to validate batch publish isolated reads fix
package server

import (
	"fmt"
	"strconv"
	"sync"
	"sync/atomic"
	"testing"
	"time"

	"github.com/nats-io/nats.go"
)

// TestBatchPublishIsolatedReadsFix validates that the isolated reads fix prevents
// readers from observing partial batch effects.
func TestBatchPublishIsolatedReadsFix(t *testing.T) {
	c := createJetStreamClusterExplicit(t, "R3S", 3)
	defer c.shutdown()

	nc, js := jsClientConnect(t, c.randomServer())
	defer nc.Close()

	cfg := &StreamConfig{
		Name:               "TEST",
		Subjects:           []string{"foo"},
		Storage:            FileStorage,
		AllowAtomicPublish: true,
		Replicas:           3,
	}
	_, err := jsStreamCreate(t, nc, cfg)
	require_NoError(t, err)

	c.waitOnStreamLeader(globalAccountName, "TEST")
	leader := c.streamLeader(globalAccountName, "TEST")

	// Get the stream to check uncommitted map
	mset, err := leader.globalAccount().lookupStream("TEST")
	require_NoError(t, err)

	var violationCount atomic.Int32
	var wg sync.WaitGroup
	stopReading := make(chan struct{})

	// Reader that checks both API and direct store access
	wg.Add(1)
	go func() {
		defer wg.Done()
		for {
			select {
			case <-stopReading:
				return
			default:
				// Try API access
				si, err := js.StreamInfo("TEST")
				if err == nil && si.State.Msgs > 0 {
					for seq := uint64(1); seq <= si.State.LastSeq; seq++ {
						msg, err := js.GetMsg("TEST", seq)
						if err != nil {
							continue
						}

						// Check if this is a batch message
						batchId := msg.Header.Get("Nats-Batch-Id")
						if batchId != "" {
							// If we see it, it better have a commit or be part of committed batch
							hasCommit := msg.Header.Get("Nats-Batch-Commit") != ""
							if !hasCommit {
								// Check if this is the last message in stream
								// If not, the commit might be coming
								if seq < si.State.LastSeq {
									// Check next message
									nextMsg, err := js.GetMsg("TEST", seq+1)
									if err != nil || nextMsg.Header.Get("Nats-Batch-Id") != batchId {
										t.Logf("Violation: Partial batch visible via API: batch=%s, seq=%d", batchId, seq)
										violationCount.Add(1)
									}
								}
							}
						}
					}
				}

				// Also check direct store access
				var state StreamState
				mset.store.FastState(&state)
				if state.Msgs > 0 {
					for seq := state.FirstSeq; seq <= state.LastSeq; seq++ {
						var smv StoreMsg
						sm, err := mset.store.LoadMsg(seq, &smv)
						if err != nil || sm == nil {
							continue
						}

						batchId := getBatchId(sm.hdr)
						if batchId != "" {
							// Check if marked as uncommitted
							isUncommitted := mset.isSeqUncommitted(seq)
							hasCommit := len(sliceHeader(JSBatchCommit, sm.hdr)) > 0

							if !hasCommit && !isUncommitted {
								t.Logf("Violation: Uncommitted batch message not marked: batch=%s, seq=%d", batchId, seq)
								violationCount.Add(1)
							}
						}
					}
				}

				time.Sleep(5 * time.Millisecond)
			}
		}
	}()

	// Publish multiple batches slowly
	for batchNum := 1; batchNum <= 3; batchNum++ {
		batchId := fmt.Sprintf("batch-%d", batchNum)
		batchSize := 5

		for seq := 1; seq <= batchSize; seq++ {
			m := nats.NewMsg("foo")
			m.Data = []byte(fmt.Sprintf("b%d-msg%d", batchNum, seq))
			m.Header.Set("Nats-Batch-Id", batchId)
			m.Header.Set("Nats-Batch-Sequence", strconv.Itoa(seq))

			if seq == batchSize {
				m.Header.Set("Nats-Batch-Commit", "1")
				_, err = nc.RequestMsg(m, 2*time.Second)
				require_NoError(t, err)
			} else {
				require_NoError(t, nc.PublishMsg(m))
				time.Sleep(10 * time.Millisecond)
			}
		}

		// Small delay between batches
		time.Sleep(50 * time.Millisecond)
	}

	// Wait for all batches to be fully committed
	time.Sleep(200 * time.Millisecond)

	// Stop reader
	close(stopReading)
	wg.Wait()

	// Check results
	if violationCount.Load() > 0 {
		t.Fatalf("Detected %d isolation violations", violationCount.Load())
	}

	// Verify final state
	si, err := js.StreamInfo("TEST")
	require_NoError(t, err)
	require_Equal(t, si.State.Msgs, uint64(15)) // 3 batches * 5 messages each

	// Verify uncommitted map is empty
	mset.batchUncommittedMu.RLock()
	uncommittedCount := len(mset.batchUncommitted)
	mset.batchUncommittedMu.RUnlock()
	if uncommittedCount != 0 {
		t.Fatalf("Expected uncommitted map to be empty, but has %d entries", uncommittedCount)
	}

	t.Logf("SUCCESS: All batches published with proper isolation. No violations detected.")
}

