package server

import (
	"strconv"
	"testing"
	"time"

	"github.com/nats-io/nats.go"
)

// TestBatchPublishIsolatedReadsSimple validates the fix with a simple scenario
func TestBatchPublishIsolatedReadsSimple(t *testing.T) {
	s := RunBasicJetStreamServer(t)
	defer s.Shutdown()

	nc, js := jsClientConnect(t, s)
	defer nc.Close()

	_, err := jsStreamCreate(t, nc, &StreamConfig{
		Name:               "TEST",
		Subjects:           []string{"foo"},
		Storage:            FileStorage,
		AllowAtomicPublish: true,
	})
	require_NoError(t, err)

	// Send first 2 messages of a 3-message batch
	for seq := 1; seq <= 2; seq++ {
		m := nats.NewMsg("foo")
		m.Data = []byte("msg" + strconv.Itoa(seq))
		m.Header.Set("Nats-Batch-Id", "test")
		m.Header.Set("Nats-Batch-Sequence", strconv.Itoa(seq))
		require_NoError(t, nc.PublishMsg(m))
	}

	// Wait a bit for messages to be processed
	time.Sleep(100 * time.Millisecond)

	// Try to read the messages - should get "not found" due to uncommitted batch
	_, err = js.GetMsg("TEST", 1)
	if err == nil {
		t.Fatal("Expected error reading uncommitted batch message, got nil")
	}

	_, err = js.GetMsg("TEST", 2)
	if err == nil {
		t.Fatal("Expected error reading uncommitted batch message, got nil")
	}

	// Now send the commit message
	m := nats.NewMsg("foo")
	m.Data = []byte("msg3")
	m.Header.Set("Nats-Batch-Id", "test")
	m.Header.Set("Nats-Batch-Sequence", "3")
	m.Header.Set("Nats-Batch-Commit", "1")
	_, err = nc.RequestMsg(m, 2*time.Second)
	require_NoError(t, err)

	// Now all messages should be readable
	msg1, err := js.GetMsg("TEST", 1)
	require_NoError(t, err)
	require_Equal(t, string(msg1.Data), "msg1")

	msg2, err := js.GetMsg("TEST", 2)
	require_NoError(t, err)
	require_Equal(t, string(msg2.Data), "msg2")

	msg3, err := js.GetMsg("TEST", 3)
	require_NoError(t, err)
	require_Equal(t, string(msg3.Data), "msg3")

	t.Log("SUCCESS: Isolated reads working correctly")
}

